import numpy as np

def select_next_node(current_node, truck_nodes, depot_node, unvisited_nodes, distance_matrix):
    """
    {The algorithm selects the next node by computing a pseudo-random priority score for each unvisited node based on a weighted combination of the inverse distance, randomness, and current load factors to balance exploration and route efficiency within a dynamic routing environment.}
    """
    # Step 1: Calculate the inverse distances for each unvisited node.
    inverse_distances = {node: 1.0 / (distance_matrix[current_node, node] + 1.e-5) for node in unvisited_nodes}

    # Step 2: Compute random factor and existing truck node factor.
    random_factor = np.random.rand(len(unvisited_nodes))
    node_load_factor = {node: np.sum(truck_nodes == node) for node in unvisited_nodes}

    # Step 3: Calculate a priority score as a combination of inverse distances, randomness, and load factors.
    scores = {node: (0.5 * inverse_distances[node] + 0.3 * random_factor[i] + 0.2 / (1 + node_load_factor[node])) 
              for i, node in enumerate(unvisited_nodes)}

    # Step 4: Select the node with the highest priority score.
    next_node = max(scores, key=scores.get)

    return next_node
